import { unstable_noStore as noStore } from "next/cache";

export type Post = {
  id: number;
  title: string;
  body: string;
};

// In-memory store (in a real app, this would be a database)
const posts: Post[] = [
  { id: 1, title: "First Post", body: "This is the first post." },
  { id: 2, title: "Second Post", body: "This is the second post." },
];

export async function getPosts(): Promise<Post[]> {
  // Tag this cached data so it can be selectively invalidated
  // The function will re-execute when revalidateTag("posts") is called
  "use cache";
  // eslint-disable-next-line @typescript-eslint/no-unused-expressions
  cacheTag("posts");

  // Simulate a data fetch delay to demonstrate caching behavior
  await new Promise((resolve) => setTimeout(resolve, 500));

  return [...posts];
}

// Add a no-store variant for use after revalidation to ensure freshness
export async function getPostsFresh(): Promise<Post[]> {
  noStore();
  return [...posts];
}

export async function addPost(
  title: string,
  body: string
): Promise<Post> {
  const id = posts.length > 0 ? Math.max(...posts.map((p) => p.id)) + 1 : 1;
  const post: Post = { id, title, body };
  posts.push(post);
  return post;
}

